-- ============================================================
-- Mental Health Clinic Operations & Patient Retention Analytics
-- Step 1: Expanded Database Schema
-- ============================================================

DROP DATABASE IF EXISTS mental_health_clinic;
CREATE DATABASE mental_health_clinic;
USE mental_health_clinic;

-- ============================================================
-- TABLE 1: therapist
-- Stores therapist profiles with specialty and hourly rate
-- ============================================================
CREATE TABLE therapist (
    therapistID INT PRIMARY KEY AUTO_INCREMENT,
    name VARCHAR(100) NOT NULL,
    specialty VARCHAR(100) NOT NULL,
    session_fee DECIMAL(6,2) NOT NULL,
    hire_date DATE NOT NULL
);

-- ============================================================
-- TABLE 2: patient
-- Stores patient demographics for segmentation analysis
-- ============================================================
CREATE TABLE patient (
    patientID INT PRIMARY KEY AUTO_INCREMENT,
    name VARCHAR(100) NOT NULL,
    phone VARCHAR(20) NOT NULL,
    age INT NOT NULL,
    gender VARCHAR(20) NOT NULL,
    insurance_type VARCHAR(50) NOT NULL,
    referral_source VARCHAR(50) NOT NULL,
    enrollment_date DATE NOT NULL
);

-- ============================================================
-- TABLE 3: assigned_to
-- Junction table: each patient assigned to exactly one therapist
-- ============================================================
CREATE TABLE assigned_to (
    patientID INT PRIMARY KEY,
    therapistID INT NOT NULL,
    startDate DATE NOT NULL,
    frequency VARCHAR(50) NOT NULL,
    FOREIGN KEY (patientID) REFERENCES patient(patientID),
    FOREIGN KEY (therapistID) REFERENCES therapist(therapistID)
);

-- ============================================================
-- TABLE 4: appointment
-- Tracks every scheduled session with status
-- ============================================================
CREATE TABLE appointment (
    appointmentID INT PRIMARY KEY AUTO_INCREMENT,
    patientID INT NOT NULL,
    therapistID INT NOT NULL,
    date DATETIME NOT NULL,
    status VARCHAR(20) NOT NULL,
    FOREIGN KEY (patientID) REFERENCES patient(patientID),
    FOREIGN KEY (therapistID) REFERENCES therapist(therapistID)
);

-- ============================================================
-- TABLE 5: session_record
-- Records completed sessions with progress tracking
-- ============================================================
CREATE TABLE session_record (
    sessionID INT PRIMARY KEY AUTO_INCREMENT,
    appointmentID INT UNIQUE NOT NULL,
    dateCompleted DATE NOT NULL,
    patientAttended BOOLEAN NOT NULL,
    progress_score INT NOT NULL CHECK (progress_score BETWEEN 1 AND 10),
    session_notes VARCHAR(255),
    FOREIGN KEY (appointmentID) REFERENCES appointment(appointmentID)
);

-- ============================================================
-- TABLE 6: mental_health_concern
-- Catalog of all mental health conditions
-- ============================================================
CREATE TABLE mental_health_concern (
    concernID INT PRIMARY KEY AUTO_INCREMENT,
    concernName VARCHAR(100) NOT NULL,
    category VARCHAR(50) NOT NULL,
    severity VARCHAR(20) NOT NULL
);

-- ============================================================
-- TABLE 7: addresses (junction table)
-- Many-to-many: sessions can address multiple concerns
-- ============================================================
CREATE TABLE addresses (
    sessionID INT NOT NULL,
    concernID INT NOT NULL,
    PRIMARY KEY (sessionID, concernID),
    FOREIGN KEY (sessionID) REFERENCES session_record(sessionID),
    FOREIGN KEY (concernID) REFERENCES mental_health_concern(concernID)
);

-- ============================================================
-- TABLE 8: billing (NEW)
-- Tracks payment for each completed session
-- ============================================================
CREATE TABLE billing (
    billingID INT PRIMARY KEY AUTO_INCREMENT,
    sessionID INT UNIQUE NOT NULL,
    amount DECIMAL(8,2) NOT NULL,
    insurance_covered DECIMAL(8,2) NOT NULL,
    patient_copay DECIMAL(8,2) NOT NULL,
    payment_status VARCHAR(20) NOT NULL,
    billing_date DATE NOT NULL,
    FOREIGN KEY (sessionID) REFERENCES session_record(sessionID)
);

-- ============================================================
-- INDEXES for performance
-- ============================================================
CREATE INDEX idx_appointment_patient ON appointment(patientID);
CREATE INDEX idx_appointment_therapist ON appointment(therapistID);
CREATE INDEX idx_appointment_date ON appointment(date);
CREATE INDEX idx_appointment_status ON appointment(status);
CREATE INDEX idx_session_date ON session_record(dateCompleted);
CREATE INDEX idx_session_progress ON session_record(progress_score);
CREATE INDEX idx_billing_date ON billing(billing_date);
CREATE INDEX idx_billing_status ON billing(payment_status);
CREATE INDEX idx_patient_insurance ON patient(insurance_type);
CREATE INDEX idx_patient_referral ON patient(referral_source);


